import{_ as e,o as a,c as n,a2 as d}from"./chunks/framework.CQMe4Urg.js";const A=JSON.parse('{"title":"第六章 Agent 核心原理 -- 从聊天机器人到自主智能体","description":"","frontmatter":{},"headers":[],"relativePath":"06-agent-basics/index.md","filePath":"06-agent-basics/index.md","lastUpdated":1776333512000}'),r={name:"06-agent-basics/index.md"};function o(i,t,l,h,s,c){return a(),n("div",null,[...t[0]||(t[0]=[d('<h1 id="第六章-agent-核心原理-从聊天机器人到自主智能体" tabindex="-1">第六章 Agent 核心原理 -- 从聊天机器人到自主智能体 <a class="header-anchor" href="#第六章-agent-核心原理-从聊天机器人到自主智能体" aria-label="Permalink to &quot;第六章 Agent 核心原理 -- 从聊天机器人到自主智能体&quot;">​</a></h1><p>上一章我们学会了 Tool Use，让 LLM 能够调用外部工具。但仅仅&quot;能调用工具&quot;还不够 -- 一个真正的 Agent 需要<strong>自主决策</strong>：分析任务、制定计划、执行操作、观察结果、反思改进，循环往复直到任务完成。</p><p><strong>Agent = LLM + 工具 + 循环 + 自主决策。</strong> 如果说 Tool Use 是给 LLM 装上了手脚，那 Agent 就是给它装上了&quot;主动做事&quot;的意识。普通聊天机器人只能一问一答，而 Agent 能接住一个复杂任务，自己拆解步骤，自己执行，自己检查结果。</p><p>这一章从 ReAct 模式讲起，手把手带你写出第一个 Agent 循环，然后深入 Planning、Reflection 等设计模式，最后探讨 Agent 的自适应和元认知机制。</p><h2 id="本章内容" tabindex="-1">本章内容 <a class="header-anchor" href="#本章内容" aria-label="Permalink to &quot;本章内容&quot;">​</a></h2><ul><li><a href="./beginner.html">入门篇</a> -- ReAct 模式、手写 Agent 循环（while + stop_reason）、对话管理基础、文件管理 Agent 实战</li><li><a href="./intermediate.html">进阶篇</a> -- Planning 规划策略、Reflection 自我反思、路由分发、人机协同</li><li><a href="./advanced.html">高级篇</a> -- 自适应策略选择、元认知机制、Agent 自我改进、高级错误恢复</li></ul><h2 id="核心概念速览" tabindex="-1">核心概念速览 <a class="header-anchor" href="#核心概念速览" aria-label="Permalink to &quot;核心概念速览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>一句话解释</th></tr></thead><tbody><tr><td>Agent</td><td>能自主决策和执行任务的 LLM 应用</td></tr><tr><td>ReAct</td><td>Reasoning + Acting，交替思考和行动的模式</td></tr><tr><td>Agent 循环</td><td>while 循环 + tool_use 检测，Agent 运行的核心引擎</td></tr><tr><td>Planning</td><td>先制定完整计划再逐步执行</td></tr><tr><td>Reflection</td><td>Agent 执行后自我反思、评估、改进</td></tr><tr><td>Router</td><td>根据任务类型分发给不同的专业处理链</td></tr><tr><td>Human-in-the-Loop</td><td>关键决策点引入人类审批</td></tr><tr><td>元认知</td><td>Agent 知道自己能做什么、不能做什么</td></tr></tbody></table><h2 id="学完你能做到" tabindex="-1">学完你能做到 <a class="header-anchor" href="#学完你能做到" aria-label="Permalink to &quot;学完你能做到&quot;">​</a></h2><table tabindex="0"><thead><tr><th>层级</th><th>能力</th></tr></thead><tbody><tr><td>入门</td><td>理解 Agent 和聊天机器人的区别、手写 ReAct Agent 循环、构建能使用工具的 Agent</td></tr><tr><td>进阶</td><td>实现 Plan-then-Execute 模式、让 Agent 自我反思改进、设计路由分发系统</td></tr><tr><td>高级</td><td>构建能根据任务难度自适应的 Agent、实现错误恢复与回滚、设计自我改进机制</td></tr></tbody></table><h2 id="前置知识" tabindex="-1">前置知识 <a class="header-anchor" href="#前置知识" aria-label="Permalink to &quot;前置知识&quot;">​</a></h2><ul><li>已完成第五章 Tool Use，理解工具定义和调用流程</li><li>熟悉 Python 面向对象编程（class, 继承）</li><li>理解异步编程基础（async/await）</li></ul>',12)])])}const u=e(r,[["render",o]]);export{A as __pageData,u as default};
